<template><div><h2>📦 我的订单</h2><div v-if="orders.length"><div v-for="o in orders" :key="o.id" class="order-card" @click="$router.push('/orders/'+o.id)"><div class="oh"><b>订单 #{{ o.id }}</b><el-tag size="small">{{ o.status }}</el-tag></div><div>¥{{ o.total_amount }} · {{ o.created_at }}</div></div></div><div v-else class="empty">暂无订单</div></div></template>
<script setup>import { ref, onMounted } from 'vue'; import request from '@/utils/request'; const orders = ref([]); onMounted(async () => { try { orders.value = await request.get('/orders/list') } catch {} });</script>
<style scoped>.order-card{padding:16px;background:#fff;border-radius:12px;margin-bottom:8px;cursor:pointer}.order-card:hover{box-shadow:0 2px 8px rgba(0,0,0,.08)}.oh{display:flex;justify-content:space-between;margin-bottom:8px}.empty{text-align:center;padding:60px;color:#B2BEC3}</style>
